const src = $node["Gemini Analyse Finale"].json || {};
let parsed = null;
try {
  const txt = src?.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  parsed = JSON.parse(txt);
} catch (e) {
  parsed = null;
}

return {
  status: 'complete',
  analysis: String(parsed?.analysis || 'Analysis complete.'),
  score: Number(parsed?.score || 80)
};
